#[op2(fast)]
pub fn bsengine_get_shield_fraction(#[string] name: String) -> f32 {
    SHIELD_SNAPSHOT.with(|s| {
        s.borrow()
            .get(&name)
            .map(|(cur, max)| {
                if *max <= 0.0 {
                    0.0
                } else {
                    (*cur / *max).clamp(0.0, 1.0)
                }
            })
            .unwrap_or(0.0)
    })
}

