pub fn bsengine_is_shield_depleted(#[string] name: String) -> bool {
    SHIELD_SNAPSHOT.with(|s| {
        s.borrow()
            .get(&name)
            .map(|(cur, _)| *cur <= 0.0)
            .unwrap_or(true)
    })
}

