#[op2(fast)]
pub fn bsengine_get_root_elapsed_fraction(#[string] name: String) -> f32 {
    ROOT_SNAPSHOT.with(|s| {
        s.borrow()
            .get(&name)
            .map(|(dur, timer, _, _, _, _, _)| {
                if *dur <= 0.0 {
                    0.0
                } else {
                    (1.0 - (*timer / *dur)).clamp(0.0, 1.0)
                }
            })
            .unwrap_or(0.0)
    })
}

