pub fn bsengine_get_freeze_state(#[string] name: String) -> u32 {
    FREEZE_SNAPSHOT.with(|s| {
        s.borrow()
            .get(&name)
            .map(|(st, _, _, _, _, _, _, _, _, _, _, _)| *st)
            .unwrap_or(0)
    })
}

