#[op2(fast)]
pub fn bsengine_get_nova_charge_fraction(#[string] name: String) -> f32 {
    NOVA_SNAPSHOT.with(|s| {
        s.borrow()
            .get(&name)
            .map(|(ct, ctr, _, _, _, _, _)| {
                if *ct <= 0.0 || *ctr <= 0.0 {
                    0.0
                } else {
                    (1.0 - ctr / ct).clamp(0.0, 1.0)
                }
            })
            .unwrap_or(0.0)
    })
}

